#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[1000010];
int n,m,k;
int dis[1000010];
bool vis[1000010];
void dijkstra(int st)
{
    priority_queue<pair<int,int>> q;
    q.push({0,st});
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    dis[st]=0;
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        int now=dis[t];
        for(auto i:mp[t])
        {
            int v=i.first,tim=i.second;
            int len=1;
            if(now<tim)
            {
                len+=(tim-now+k-1)/k*k;
            }
            if(dis[v]>dis[t]+len)
            {
                dis[v]=dis[t]+len;
                q.push({-dis[v],v});
            }
        }
    }
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        int u,v,a;
        scanf("%d%d%d",&u,&v,&a);
        for(int j=0;j<k;j++)
        {
            mp[j*n+u].push_back(make_pair(((j+1)%k)*n+v,a));
        }
    }
    dijkstra(1);
    if(dis[n]>1e9)
    {
        dis[n]=-1;
    }
    printf("%d",dis[n]);
    return 0;
}
